import axios from "axios";
class ApiService {
  constructor() {
    this.baseURL = window.JCA_LOCATIONDEVIS_CONFIG?.apiBaseUrl;
    this.token = window.JCA_LOCATIONDEVIS_CONFIG?.token || "";

    // Configuration Axios
    this.axios = axios.create({
      baseURL: this.baseURL,
      timeout: 15000,
      headers: {
        "Content-Type": "application/json",
        "X-Requested-With": "XMLHttpRequest"
      }
    });

    // Intercepteur pour ajouter le token CSRF
    this.axios.interceptors.request.use(config => {
      if (this.token) {
        config.headers.Authorization = `Bearer ${this.token}`;
      }
      return config;
    }, error => Promise.reject(error));

    // Intercepteur pour gérer les réponses
    this.axios.interceptors.response.use(response => response, error => {
      if (error.response) {
        const status = error.response.status;
        if (status === 401) {
          console.error("🔒 Token invalide ou expiré");
        } else if (status === 403) {
          console.error("🚫 Accès refusé");
        } else if (status === 404) {
          console.error("🔍 Endpoint non trouvé");
        } else if (status >= 500) {
          console.error("🔥 Erreur serveur");
        }
      }
      return Promise.reject(error);
    });
  }
  async request(action, data = {}) {
    try {
      const payload = {
        action,
        ...data
      };
      const response = await this.axios.post("", payload);
      return response.data;
    } catch (error) {
      if (error.request) {
        throw new Error("Erreur de connexion au serveur PrestaShop");
      }
      throw error;
    }
  }
  async get(endpoint, params = {}) {
    console.log("GET", endpoint, params);
    return;
    return this.axios.get(endpoint, {
      params
    });
  }
  async post(endpoint, data) {
    return this.axios.post(endpoint, data);
  }
  async put(endpoint, data) {
    return this.axios.put(endpoint, data);
  }
  async delete(endpoint) {
    return this.axios.delete(endpoint);
  }
  async patch(endpoint, data) {
    return this.axios.patch(endpoint, data);
  }
}
export default new ApiService();
